// 妖股挖掘参数计算
const now = new Date();
const hour = now.getHours();
const dayOfWeek = now.getDay();

// 非交易日: 周六日跳过
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return [{ json: { skip: true, reason: '非交易日' } }];
}

// 盘前 (9:10): 挖掘振幅压缩+量价共振，预测当日启动
if (hour === 9) {
  return [{ json: {
    skip: false,
    rounds: 2,
    factors_per_round: 5,
    focus_theme: 'yao_amplitude_compression',
    session_label: '盘前-振幅压缩'
  }}];
}

// 午盘 (11:30): 挖掘开盘强度+尾盘特征
if (hour === 11) {
  return [{ json: {
    skip: false,
    rounds: 2,
    factors_per_round: 5,
    focus_theme: 'yao_opening_attack',
    session_label: '午盘-竞价强势'
  }}];
}

// 盘后 (15:05): 全主题随机挖掘，样本最全
if (hour === 15) {
  return [{ json: {
    skip: false,
    rounds: 3,
    factors_per_round: 5,
    focus_theme: null,
    session_label: '盘后-全主题'
  }}];
}

// 夜间 (20:30): 挖掘连板动量+筹码整理
if (hour === 20) {
  return [{ json: {
    skip: false,
    rounds: 3,
    factors_per_round: 5,
    focus_theme: 'yao_chip_consolidation',
    session_label: '夜间-筹码蓄势'
  }}];
}

return [{ json: { skip: true, reason: 'unexpected hour' } }];

