const result = $input.item.json;
const label = $('0. 计算妖股挖掘参数').item.json.session_label || '妖股挖掘';

if (result.skipped) {
  console.log(`[妖股] ${label} - 跳过: ${result.message}`);
  return [{ json: { status: 'skipped', label } }];
}

console.log(`[妖股] ${label} - 已启动: ${result.message}`);
return [{ json: { status: 'started', label, message: result.message } }];
